#!/usr/bin/env python3
"""CLI tool to compute basic statistics for numeric columns in a CSV file."""

import argparse
import csv
import sys
from collections import defaultdict


def parse_args():
    parser = argparse.ArgumentParser(
        description="Read a CSV file and print count, mean, min, max for each numeric column."
    )
    parser.add_argument(
        "input_file",
        help="Path to the input CSV file",
    )
    return parser.parse_args()


def is_numeric(value):
    """Check if a string value can be converted to a float."""
    try:
        float(value)
        return True
    except (ValueError, TypeError):
        return False


def read_csv_stats(input_file):
    """Read the CSV file and compute statistics for numeric columns."""
    column_values = defaultdict(list)
    column_names = []

    try:
        with open(input_file, "r", newline="", encoding="utf-8") as f:
            reader = csv.reader(f)

            # Read header
            try:
                header = next(reader)
            except StopIteration:
                print("Error: CSV file is empty.", file=sys.stderr)
                sys.exit(1)

            column_names = [h.strip() for h in header]

            # Read data rows
            for row_num, row in enumerate(reader, start=2):
                for i, value in enumerate(row):
                    if i < len(column_names):
                        col_name = column_names[i]
                        stripped = value.strip()
                        if stripped == "":
                            # Skip empty values
                            continue
                        if is_numeric(stripped):
                            column_values[col_name].append(float(stripped))
                        # Non-numeric columns are silently ignored

    except FileNotFoundError:
        print(f"Error: File '{input_file}' not found.", file=sys.stderr)
        sys.exit(1)
    except Exception as e:
        print(f"Error reading file: {e}", file=sys.stderr)
        sys.exit(1)

    return column_names, column_values


def compute_stats(values):
    """Compute count, mean, min, max for a list of numeric values."""
    count = len(values)
    if count == 0:
        return None
    mean = sum(values) / count
    min_val = min(values)
    max_val = max(values)
    return {
        "count": count,
        "mean": mean,
        "min": min_val,
        "max": max_val,
    }


